#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int id;
    char name[101];
    double price;
} Product;

void apply_discount(Product *p, int d) {
    p->price = p->price - (p->price * d / 100.0);
}

void display(const Product *p) {
    printf("ID: %d, Name: %s, Price: %.2f\n", p->id, p->name, p->price);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Product *arr = (Product*)malloc(N * sizeof(Product));
        for (int i = 0; i < N; ++i) {
            scanf("%d %100s %lf", &arr[i].id, arr[i].name, &arr[i].price);
        }
        int D;
        scanf("%d", &D);
        for (int i = 0; i < N; ++i) {
            apply_discount(&arr[i], D);
            display(&arr[i]);
        }
        free(arr);
    }
    return 0;
}

