#include <bits/stdc++.h>
using namespace std;

class Product {
public:
    int id;
    string name;
    double price;
    Product(int i, const string& n, double p) : id(i), name(n), price(p) {}
    void apply_discount(int d) { price -= price * d / 100.0; }
    void display() const {
        cout << "ID: " << id << ", Name: " << name << ", Price: " << fixed << setprecision(2) << price << '\n';
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        vector<Product> prod; prod.reserve(N);
        for (int i=0;i<N;++i) {
            int id; string name; double price; cin>>id>>name>>price;
            prod.emplace_back(id,name,price);
        }
        int D; cin>>D;
        for (auto &p: prod) {
            p.apply_discount(D);
            p.display();
        }
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

class Product {
    int id;
    String name;
    double price;
    Product(int id, String name, double price) {
        this.id = id;
        this.name = name;
        this.price = price;
    }
    void applyDiscount(int d) {
        price = price - (price * d / 100.0);
    }
    void appendDisplay(StringBuilder sb) {
        sb.append("ID: ").append(id)
          .append(", Name: ").append(name)
          .append(", Price: ")
          .append(String.format(Locale.US, "%.2f", price))
          .append('\n');
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Product> list = new ArrayList<>(N);
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int id = Integer.parseInt(st.nextToken());
                String name = st.nextToken();
                double price = Double.parseDouble(st.nextToken());
                list.add(new Product(id, name, price));
            }
            int D = Integer.parseInt(br.readLine().trim());
            for (Product p : list) {
                p.applyDiscount(D);
                p.appendDisplay(out);
            }
        }
        System.out.print(out.toString());
    }
}

