#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        products = []
        for _ in range(N):
            pid, pname, pprice = data[idx].split(); idx += 1
            products.append((int(pid), pname, float(pprice)))
        D = int(data[idx].strip()); idx += 1
        for pid, pname, pprice in products:
            new_price = pprice - (pprice * D / 100.0)
            out_lines.append(f"ID: {pid}, Name: {pname}, Price: {new_price:.2f}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

